import java.time.LocalTime;

public class Main {
    public static void main(String[] args) {
        // 現在の時間を取得
        LocalTime now = LocalTime.now();
        // 比較の基準となる時間を設定
        LocalTime compareTime = LocalTime.of(13, 30);

        // 現在の時間が13:30より後かどうかを比較
        if (now.isAfter(compareTime)) {
            System.out.println("It's after 13:30 now."); // 出力例：It's after 13:30 now.
        } else {
            System.out.println("It's before 13:30 now."); // 出力例：It's before 13:30 now.
        }
    }
}

import java.time.LocalTime;
import java.time.Duration;

public class Main {
    public static void main(String[] args) {
        // 現在の時間を取得
        LocalTime now = LocalTime.now();
        // 比較の基準となる時間を設定
        LocalTime startTime = LocalTime.of(8, 0);

        // 2つの時間の間の時間を計算
        Duration duration = Duration.between(startTime, now);

        // 時間と分を表示
        long hours = duration.toHours();
        long minutes = duration.toMinutes() - hours * 60;
        System.out.println("Hours: " + hours + ", Minutes: " + minutes); // 出力例：Hours: 4, Minutes: 30
    }
}

