import java.time.LocalTime;
import java.time.temporal.ChronoUnit;

public class Main {
    public static void main(String[] args) {
        // 現在の時間を取得
        LocalTime now = LocalTime.now();
        // 次の12:00の時間を設定
        LocalTime noon = LocalTime.of(12, 0);

        if (now.isAfter(noon)) {
            // 現在の時間が12:00を過ぎていれば、次の日の12:00を設定
            noon = noon.plusDays(1);
        }

        // 残り時間を計算
        long hours = ChronoUnit.HOURS.between(now, noon);
        long minutes = ChronoUnit.MINUTES.between(now.plusHours(hours), noon);
        long seconds = ChronoUnit.SECONDS.between(now.plusHours(hours).plusMinutes(minutes), noon);

        // 残り時間を出力
        System.out.println(hours + " hours " + minutes + " minutes " + seconds + " seconds"); // 例の出力: 2 hours 30 minutes 20 seconds
    }
}

import java.time.LocalTime;
import java.time.temporal.ChronoUnit;

public class Main {
    public static void main(String[] args) {
        // 時間を設定
        LocalTime time1 = LocalTime.of(12, 0, 0);
        LocalTime time2 = LocalTime.of(15, 30, 20);

        // 時間の差を計算
        long hours = ChronoUnit.HOURS.between(time1, time2);
        long minutes = ChronoUnit.MINUTES.between(time1.plusHours(hours), time2);
        long seconds = ChronoUnit.SECONDS.between(time1.plusHours(hours).plusMinutes(minutes), time2);

        // 時間の差を出力
        System.out.println(hours + " hours " + minutes + " minutes " + seconds + " seconds"); // 出力: 3 hours 30 minutes 20 seconds
    }
}

