import java.time.LocalTime;
import java.time.temporal.ChronoUnit;

public class Main {
    public static void main(String[] args) {
        // 2つの時間を定義
        LocalTime time1 = LocalTime.of(8, 0);
        LocalTime time2 = LocalTime.of(10, 30);

        // 時間の差を計算
